HTML_PAGE = '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n  <title>Valorant Fanbase API</title>\n  <link rel="preconnect" href="https://fonts.googleapis.com"/>\n  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin/>\n  <link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Barlow+Condensed:ital,wght@0,300;0,400;0,600;1,400&family=Share+Tech+Mono&display=swap" rel="stylesheet"/>\n  <style>\n    :root {\n      --red: #ff4655;\n      --red-dim: #c0313e;\n      --gold: #f0b232;\n      --white: #ece8e1;\n      --dark: #0f1923;\n      --dark2: #1a2634;\n      --dark3: #253040;\n      --muted: #7b8a96;\n      --green: #00c896;\n    }\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n    body {\n      background: var(--dark);\n      color: var(--white);\n      font-family: \'Barlow Condensed\', sans-serif;\n      font-size: 16px;\n      min-height: 100vh;\n      overflow-x: hidden;\n    }\n\n    /* ── HEADER ── */\n    header {\n      position: relative;\n      padding: 40px 40px 24px;\n      border-bottom: 2px solid var(--red);\n      display: flex;\n      align-items: flex-end;\n      gap: 20px;\n      background: linear-gradient(135deg, var(--dark) 60%, #1e0a0e);\n      overflow: hidden;\n    }\n    header::before {\n      content: \'\';\n      position: absolute;\n      inset: 0;\n      background: repeating-linear-gradient(\n        -55deg,\n        transparent,\n        transparent 18px,\n        rgba(255,70,85,0.03) 18px,\n        rgba(255,70,85,0.03) 19px\n      );\n      pointer-events: none;\n    }\n    .logo-mark {\n      font-family: \'Rajdhani\', sans-serif;\n      font-weight: 700;\n      font-size: 44px;\n      color: var(--red);\n      letter-spacing: -2px;\n      line-height: 1;\n      position: relative;\n    }\n    .logo-mark span { color: var(--white); }\n    .header-sub {\n      font-size: 13px;\n      color: var(--muted);\n      letter-spacing: 3px;\n      text-transform: uppercase;\n      padding-bottom: 6px;\n    }\n    .status-pill {\n      margin-left: auto;\n      display: flex;\n      align-items: center;\n      gap: 8px;\n      background: rgba(0,200,150,0.1);\n      border: 1px solid var(--green);\n      border-radius: 2px;\n      padding: 6px 14px;\n      font-family: \'Share Tech Mono\', monospace;\n      font-size: 12px;\n      color: var(--green);\n    }\n    .status-dot {\n      width: 7px; height: 7px;\n      border-radius: 50%;\n      background: var(--green);\n      animation: pulse 1.8s infinite;\n    }\n    @keyframes pulse {\n      0%,100% { opacity:1; } 50% { opacity:0.3; }\n    }\n\n    /* ── NAV ── */\n    nav {\n      display: flex;\n      gap: 0;\n      background: var(--dark2);\n      border-bottom: 1px solid var(--dark3);\n      padding: 0 40px;\n    }\n    nav button {\n      background: none; border: none; cursor: pointer;\n      color: var(--muted);\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 15px;\n      font-weight: 600;\n      letter-spacing: 2px;\n      text-transform: uppercase;\n      padding: 16px 24px;\n      border-bottom: 3px solid transparent;\n      transition: all 0.2s;\n    }\n    nav button:hover { color: var(--white); }\n    nav button.active { color: var(--red); border-bottom-color: var(--red); }\n\n    /* ── MAIN ── */\n    main { padding: 32px 40px; max-width: 1400px; }\n\n    /* ── ENDPOINT CARD ── */\n    .endpoint-grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));\n      gap: 16px;\n      margin-bottom: 32px;\n    }\n    .endpoint-card {\n      background: var(--dark2);\n      border: 1px solid var(--dark3);\n      border-left: 3px solid var(--red);\n      padding: 20px 24px;\n      cursor: pointer;\n      transition: all 0.2s;\n      position: relative;\n      overflow: hidden;\n    }\n    .endpoint-card:hover {\n      border-color: var(--red);\n      background: #1e2d3f;\n      transform: translateY(-2px);\n    }\n    .endpoint-card::after {\n      content: \'\';\n      position: absolute;\n      top: 0; right: 0;\n      border-style: solid;\n      border-width: 0 20px 20px 0;\n      border-color: transparent var(--dark3) transparent transparent;\n    }\n    .ep-method {\n      font-family: \'Share Tech Mono\', monospace;\n      font-size: 11px;\n      color: var(--green);\n      letter-spacing: 1px;\n      margin-bottom: 6px;\n    }\n    .ep-path {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 20px;\n      font-weight: 700;\n      color: var(--white);\n      margin-bottom: 6px;\n    }\n    .ep-desc {\n      font-size: 13px;\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    /* ── AGENT GRID ── */\n    .agents-section { display: none; }\n    .agents-section.active { display: block; }\n    .agents-header {\n      display: flex;\n      align-items: center;\n      gap: 16px;\n      margin-bottom: 24px;\n    }\n    .section-title {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 28px;\n      font-weight: 700;\n      letter-spacing: 2px;\n      text-transform: uppercase;\n      color: var(--white);\n    }\n    .section-title span { color: var(--red); }\n    .role-filter {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n      margin-bottom: 24px;\n    }\n    .role-btn {\n      background: var(--dark2);\n      border: 1px solid var(--dark3);\n      color: var(--muted);\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 13px;\n      font-weight: 600;\n      letter-spacing: 1px;\n      text-transform: uppercase;\n      padding: 7px 16px;\n      cursor: pointer;\n      transition: all 0.2s;\n      border-radius: 1px;\n    }\n    .role-btn:hover, .role-btn.active {\n      background: var(--red);\n      border-color: var(--red);\n      color: var(--white);\n    }\n    .agents-grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));\n      gap: 16px;\n    }\n    .agent-card {\n      background: var(--dark2);\n      border: 1px solid var(--dark3);\n      cursor: pointer;\n      overflow: hidden;\n      transition: all 0.25s;\n      position: relative;\n    }\n    .agent-card:hover {\n      transform: translateY(-4px);\n      border-color: var(--red);\n    }\n    .agent-card:hover .agent-name-bar { background: var(--red); }\n    .agent-portrait {\n      width: 100%;\n      aspect-ratio: 9/16;\n      object-fit: cover;\n      object-position: top center;\n      display: block;\n      background: var(--dark3);\n    }\n    .agent-name-bar {\n      background: var(--dark3);\n      padding: 10px 14px;\n      transition: background 0.2s;\n    }\n    .agent-name {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 18px;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 1px;\n    }\n    .agent-role-tag {\n      font-size: 11px;\n      color: var(--muted);\n      letter-spacing: 1px;\n      text-transform: uppercase;\n      margin-top: 2px;\n    }\n\n    /* ── DETAIL PANEL ── */\n    .detail-overlay {\n      display: none;\n      position: fixed;\n      inset: 0;\n      background: rgba(0,0,0,0.75);\n      z-index: 100;\n      overflow-y: auto;\n    }\n    .detail-overlay.open { display: flex; align-items: flex-start; justify-content: center; padding: 40px 20px; }\n    .detail-panel {\n      background: var(--dark2);\n      border: 1px solid var(--dark3);\n      border-top: 3px solid var(--red);\n      max-width: 800px;\n      width: 100%;\n      display: grid;\n      grid-template-columns: 240px 1fr;\n      gap: 0;\n      overflow: hidden;\n      animation: slideUp 0.3s ease;\n    }\n    @keyframes slideUp {\n      from { transform: translateY(30px); opacity: 0; }\n      to   { transform: translateY(0);    opacity: 1; }\n    }\n    .detail-portrait-col {\n      position: relative;\n      overflow: hidden;\n    }\n    .detail-portrait {\n      width: 100%;\n      height: 100%;\n      min-height: 400px;\n      object-fit: cover;\n      object-position: top center;\n      display: block;\n    }\n    .detail-portrait-overlay {\n      position: absolute;\n      inset: 0;\n      background: linear-gradient(to right, transparent 50%, var(--dark2));\n    }\n    .detail-content { padding: 32px; }\n    .detail-role-badge {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      background: rgba(255,70,85,0.1);\n      border: 1px solid var(--red);\n      padding: 4px 12px;\n      font-size: 12px;\n      letter-spacing: 2px;\n      text-transform: uppercase;\n      color: var(--red);\n      margin-bottom: 12px;\n    }\n    .detail-role-icon { width: 16px; height: 16px; filter: invert(40%) sepia(80%) saturate(500%) hue-rotate(320deg); }\n    .detail-name {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 42px;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 2px;\n      line-height: 1;\n      margin-bottom: 16px;\n    }\n    .detail-desc {\n      font-size: 15px;\n      color: var(--muted);\n      line-height: 1.65;\n      margin-bottom: 28px;\n    }\n    .abilities-title {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 14px;\n      font-weight: 700;\n      letter-spacing: 3px;\n      text-transform: uppercase;\n      color: var(--gold);\n      margin-bottom: 14px;\n      display: flex;\n      align-items: center;\n      gap: 10px;\n    }\n    .abilities-title::after {\n      content: \'\';\n      flex: 1;\n      height: 1px;\n      background: var(--dark3);\n    }\n    .ability-row {\n      display: flex;\n      align-items: flex-start;\n      gap: 14px;\n      margin-bottom: 14px;\n    }\n    .ability-icon {\n      width: 36px;\n      height: 36px;\n      object-fit: contain;\n      background: var(--dark3);\n      padding: 4px;\n      flex-shrink: 0;\n      border: 1px solid var(--dark3);\n    }\n    .ability-info {}\n    .ability-name {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 16px;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 1px;\n    }\n    .ability-desc {\n      font-size: 13px;\n      color: var(--muted);\n      line-height: 1.5;\n      margin-top: 2px;\n    }\n    .detail-close {\n      position: absolute;\n      top: 12px; right: 16px;\n      background: none;\n      border: none;\n      color: var(--muted);\n      font-size: 28px;\n      cursor: pointer;\n      line-height: 1;\n      transition: color 0.2s;\n      z-index: 10;\n    }\n    .detail-close:hover { color: var(--red); }\n\n    /* ── API EXPLORER ── */\n    .explorer-section { display: none; }\n    .explorer-section.active { display: block; }\n    .explorer-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }\n    .explorer-box { background: var(--dark2); border: 1px solid var(--dark3); padding: 24px; }\n    .box-label {\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 13px;\n      font-weight: 600;\n      letter-spacing: 2px;\n      text-transform: uppercase;\n      color: var(--muted);\n      margin-bottom: 12px;\n    }\n    .url-row { display: flex; gap: 8px; margin-bottom: 16px; }\n    .url-input {\n      flex: 1;\n      background: var(--dark);\n      border: 1px solid var(--dark3);\n      color: var(--white);\n      font-family: \'Share Tech Mono\', monospace;\n      font-size: 13px;\n      padding: 10px 14px;\n      outline: none;\n      transition: border-color 0.2s;\n    }\n    .url-input:focus { border-color: var(--red); }\n    .send-btn {\n      background: var(--red);\n      border: none;\n      color: var(--white);\n      font-family: \'Rajdhani\', sans-serif;\n      font-size: 15px;\n      font-weight: 700;\n      letter-spacing: 2px;\n      text-transform: uppercase;\n      padding: 10px 22px;\n      cursor: pointer;\n      transition: background 0.2s;\n    }\n    .send-btn:hover { background: var(--red-dim); }\n    .quick-links { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 16px; }\n    .quick-link {\n      background: var(--dark3);\n      border: none;\n      color: var(--muted);\n      font-family: \'Share Tech Mono\', monospace;\n      font-size: 11px;\n      padding: 5px 10px;\n      cursor: pointer;\n      transition: all 0.2s;\n    }\n    .quick-link:hover { background: var(--dark); color: var(--white); }\n    .response-box {\n      background: var(--dark);\n      border: 1px solid var(--dark3);\n      font-family: \'Share Tech Mono\', monospace;\n      font-size: 12px;\n      padding: 16px;\n      min-height: 200px;\n      max-height: 480px;\n      overflow-y: auto;\n      white-space: pre-wrap;\n      word-break: break-all;\n      color: var(--green);\n      line-height: 1.6;\n    }\n    .loading-dots::after {\n      content: \'\';\n      animation: dots 1.2s steps(4, end) infinite;\n    }\n    @keyframes dots {\n      0%   { content: \'\'; }\n      25%  { content: \'.\'; }\n      50%  { content: \'..\'; }\n      75%  { content: \'...\'; }\n      100% { content: \'\'; }\n    }\n    .err { color: var(--red); }\n    .spinner { display: inline-block; animation: spin 0.8s linear infinite; }\n    @keyframes spin { to { transform: rotate(360deg); } }\n\n    @media (max-width: 768px) {\n      header { padding: 24px 20px 16px; flex-wrap: wrap; }\n      main { padding: 20px; }\n      nav { padding: 0 20px; overflow-x: auto; }\n      .detail-panel { grid-template-columns: 1fr; }\n      .detail-portrait-col { max-height: 260px; }\n      .explorer-grid { grid-template-columns: 1fr; }\n    }\n  </style>\n</head>\n<body>\n\n<header>\n  <div>\n    <div class="logo-mark">VAL<span>/</span>API</div>\n    <div class="header-sub">Valorant Fanbase API &nbsp;·&nbsp; Built with FastAPI</div>\n  </div>\n  <div class="status-pill"><span class="status-dot"></span>ONLINE</div>\n</header>\n\n<nav>\n  <button class="active" onclick="showTab(\'overview\')">Overview</button>\n  <button onclick="showTab(\'agents\')">Agents</button>\n  <button onclick="showTab(\'explorer\')">API Explorer</button>\n</nav>\n\n<main>\n\n  <!-- OVERVIEW -->\n  <div id="tab-overview">\n    <div style="margin-bottom:28px;">\n      <div class="section-title" style="margin-bottom:8px;">Valorant <span>Fanbase</span> API</div>\n      <p style="color:var(--muted);font-size:15px;max-width:640px;line-height:1.7;">\n        A FastAPI wrapper around <strong style="color:var(--white)">valorant-api.com</strong> providing clean endpoints for\n        characters, roles, abilities, and actors — structured like a fanbase wiki.\n      </p>\n    </div>\n    <div class="endpoint-grid">\n      <div class="endpoint-card" onclick="goToExplorer(\'/characters\')">\n        <div class="ep-method">GET</div>\n        <div class="ep-path">/characters</div>\n        <div class="ep-desc">List all Valorant agents with portraits, roles, and icons.</div>\n      </div>\n      <div class="endpoint-card" onclick="goToExplorer(\'/characters/jett\')">\n        <div class="ep-method">GET</div>\n        <div class="ep-path">/characters/{name}</div>\n        <div class="ep-desc">Get a single agent\'s full profile, abilities, and background colors.</div>\n      </div>\n      <div class="endpoint-card" onclick="goToExplorer(\'/actors\')">\n        <div class="ep-method">GET</div>\n        <div class="ep-path">/actors</div>\n        <div class="ep-desc">Simplified cast list — all agents with role and icon only.</div>\n      </div>\n      <div class="endpoint-card" onclick="window.open(\'/docs\',\'_blank\')">\n        <div class="ep-method">DOCS</div>\n        <div class="ep-path">/docs</div>\n        <div class="ep-desc">Auto-generated Swagger UI with full interactive documentation.</div>\n      </div>\n    </div>\n    <div style="margin-top:8px;font-size:13px;color:var(--muted);">\n      Data sourced from <a href="https://valorant-api.com" target="_blank" style="color:var(--red);">valorant-api.com</a> — unofficial fan project, not affiliated with Riot Games.\n    </div>\n  </div>\n\n  <!-- AGENTS -->\n  <div id="tab-agents" class="agents-section">\n    <div class="agents-header">\n      <div class="section-title">Agent <span>Roster</span></div>\n      <div id="agent-count" style="color:var(--muted);font-size:14px;"></div>\n    </div>\n    <div class="role-filter" id="role-filter"></div>\n    <div class="agents-grid" id="agents-grid">\n      <div style="color:var(--muted);font-size:14px;">Loading agents<span class="loading-dots"></span></div>\n    </div>\n  </div>\n\n  <!-- EXPLORER -->\n  <div id="tab-explorer" class="explorer-section">\n    <div class="section-title" style="margin-bottom:20px;">API <span>Explorer</span></div>\n    <div class="explorer-grid">\n      <div class="explorer-box">\n        <div class="box-label">Request</div>\n        <div class="url-row">\n          <input class="url-input" id="api-url" value="/characters" placeholder="/characters or /characters/jett"/>\n          <button class="send-btn" onclick="sendRequest()">SEND</button>\n        </div>\n        <div class="box-label">Quick Endpoints</div>\n        <div class="quick-links">\n          <button class="quick-link" onclick="setUrl(\'/characters\')">GET /characters</button>\n          <button class="quick-link" onclick="setUrl(\'/actors\')">GET /actors</button>\n          <button class="quick-link" onclick="setUrl(\'/characters/jett\')">GET /characters/jett</button>\n          <button class="quick-link" onclick="setUrl(\'/characters/reyna\')">GET /characters/reyna</button>\n          <button class="quick-link" onclick="setUrl(\'/characters/sage\')">GET /characters/sage</button>\n          <button class="quick-link" onclick="setUrl(\'/characters/omen\')">GET /characters/omen</button>\n        </div>\n      </div>\n      <div class="explorer-box">\n        <div class="box-label">Response</div>\n        <div class="response-box" id="response-box">// Hit SEND to query the API</div>\n      </div>\n    </div>\n  </div>\n\n</main>\n\n<!-- AGENT DETAIL OVERLAY -->\n<div class="detail-overlay" id="detail-overlay" onclick="closeDetail(event)">\n  <div class="detail-panel" id="detail-panel">\n    <button class="detail-close" onclick="closeOverlay()">×</button>\n    <div class="detail-portrait-col">\n      <img class="detail-portrait" id="d-portrait" src="" alt=""/>\n      <div class="detail-portrait-overlay"></div>\n    </div>\n    <div class="detail-content">\n      <div class="detail-role-badge" id="d-role-badge">\n        <img class="detail-role-icon" id="d-role-icon" src="" alt=""/>\n        <span id="d-role-text"></span>\n      </div>\n      <div class="detail-name" id="d-name"></div>\n      <div class="detail-desc" id="d-desc"></div>\n      <div class="abilities-title">Abilities</div>\n      <div id="d-abilities"></div>\n    </div>\n  </div>\n</div>\n\n<script>\n  let allAgents = [];\n  let activeRole = \'All\';\n\n  function showTab(tab) {\n    document.querySelectorAll(\'nav button\').forEach((b,i) => b.classList.remove(\'active\'));\n    const tabs = [\'overview\',\'agents\',\'explorer\'];\n    document.querySelectorAll(\'nav button\')[tabs.indexOf(tab)].classList.add(\'active\');\n\n    document.getElementById(\'tab-overview\').style.display = tab === \'overview\' ? \'\' : \'none\';\n    document.getElementById(\'tab-agents\').classList.toggle(\'active\', tab === \'agents\');\n    document.getElementById(\'tab-explorer\').classList.toggle(\'active\', tab === \'explorer\');\n\n    if (tab === \'agents\' && allAgents.length === 0) loadAgents();\n  }\n  document.getElementById(\'tab-overview\').style.display = \'\';\n\n  async function loadAgents() {\n    try {\n      const res = await fetch(\'/characters\');\n      const json = await res.json();\n      allAgents = json.characters || [];\n      document.getElementById(\'agent-count\').textContent = `${allAgents.length} agents`;\n\n      const roles = [\'All\', ...new Set(allAgents.map(a => a.role).filter(Boolean))];\n      const rf = document.getElementById(\'role-filter\');\n      rf.innerHTML = roles.map(r =>\n        `<button class="role-btn ${r===\'All\'?\'active\':\'\'}" onclick="filterRole(\'${r}\')">${r}</button>`\n      ).join(\'\');\n\n      renderAgents(allAgents);\n    } catch(e) {\n      document.getElementById(\'agents-grid\').innerHTML = `<div class="err">Failed to load agents: ${e.message}</div>`;\n    }\n  }\n\n  function filterRole(role) {\n    activeRole = role;\n    document.querySelectorAll(\'.role-btn\').forEach(b => b.classList.toggle(\'active\', b.textContent === role));\n    const filtered = role === \'All\' ? allAgents : allAgents.filter(a => a.role === role);\n    renderAgents(filtered);\n  }\n\n  function renderAgents(agents) {\n    const grid = document.getElementById(\'agents-grid\');\n    if (!agents.length) { grid.innerHTML = \'<div style="color:var(--muted)">No agents found.</div>\'; return; }\n    grid.innerHTML = agents.map(a => `\n      <div class="agent-card" onclick="openAgent(\'${a.name}\')">\n        <img class="agent-portrait"\n          src="${a.portrait || a.icon || \'\'}"\n          alt="${a.name}"\n          onerror="this.src=\'${a.icon||\'\'}\';this.onerror=null"/>\n        <div class="agent-name-bar">\n          <div class="agent-name">${a.name}</div>\n          <div class="agent-role-tag">${a.role || \'—\'}</div>\n        </div>\n      </div>\n    `).join(\'\');\n  }\n\n  async function openAgent(name) {\n    try {\n      const res = await fetch(`/characters/${encodeURIComponent(name)}`);\n      const a = await res.json();\n      document.getElementById(\'d-portrait\').src = a.portrait || a.icon || \'\';\n      document.getElementById(\'d-name\').textContent = a.name;\n      document.getElementById(\'d-desc\').textContent = a.description || \'\';\n      document.getElementById(\'d-role-text\').textContent = a.role || \'\';\n      if (a.role_icon) {\n        document.getElementById(\'d-role-icon\').src = a.role_icon;\n        document.getElementById(\'d-role-icon\').style.display = \'\';\n      } else {\n        document.getElementById(\'d-role-icon\').style.display = \'none\';\n      }\n      const abHtml = (a.abilities || []).filter(ab => ab.name && ab.icon).map(ab => `\n        <div class="ability-row">\n          <img class="ability-icon" src="${ab.icon}" alt="${ab.name}" onerror="this.style.display=\'none\'"/>\n          <div class="ability-info">\n            <div class="ability-name">${ab.name}</div>\n            <div class="ability-desc">${ab.description || \'\'}</div>\n          </div>\n        </div>\n      `).join(\'\');\n      document.getElementById(\'d-abilities\').innerHTML = abHtml;\n      document.getElementById(\'detail-overlay\').classList.add(\'open\');\n    } catch(e) { alert(\'Could not load agent: \' + e.message); }\n  }\n\n  function closeDetail(e) { if (e.target === e.currentTarget) closeOverlay(); }\n  function closeOverlay() { document.getElementById(\'detail-overlay\').classList.remove(\'open\'); }\n\n  // Explorer\n  function setUrl(url) { document.getElementById(\'api-url\').value = url; }\n  function goToExplorer(url) {\n    showTab(\'explorer\');\n    setUrl(url);\n    sendRequest();\n  }\n\n  async function sendRequest() {\n    const path = document.getElementById(\'api-url\').value.trim();\n    const box = document.getElementById(\'response-box\');\n    box.textContent = \'// Loading...\';\n    box.className = \'response-box\';\n    try {\n      const res = await fetch(path);\n      const json = await res.json();\n      box.textContent = JSON.stringify(json, null, 2);\n      box.className = res.ok ? \'response-box\' : \'response-box err\';\n    } catch(e) {\n      box.textContent = `// Error: ${e.message}`;\n      box.className = \'response-box err\';\n    }\n  }\n  document.getElementById(\'api-url\').addEventListener(\'keydown\', e => {\n    if (e.key === \'Enter\') sendRequest();\n  });\n</script>\n</body>\n</html>\n'

async def fetch_from_valorant(path: str, params: dict = None):
    async with httpx.AsyncClient(timeout=10.0) as client:
        url = f"{VALORANT_API_BASE}{path}"
        resp = await client.get(url, params=params)
        resp.raise_for_status()
        return resp.json()


@app.get("/characters", summary="List all Valorant agents/characters")
async def get_all_characters(language: Optional[str] = "en-US"):
    data = await fetch_from_valorant("/agents", params={"language": language, "isPlayableCharacter": "true"})
    agents = data.get("data", [])
    return {
        "count": len(agents),
        "characters": [
            {
                "uuid": a["uuid"],
                "name": a["displayName"],
                "role": a.get("role", {}).get("displayName") if a.get("role") else None,
                "description": a.get("description"),
                "portrait": a.get("fullPortraitV2") or a.get("fullPortrait"),
                "icon": a.get("displayIcon"),
                "background": a.get("background"),
                "role_icon": a.get("role", {}).get("displayIcon") if a.get("role") else None,
            }
            for a in agents
        ]
    }


@app.get("/characters/{name}", summary="Get a single character by name")
async def get_character(name: str, language: Optional[str] = "en-US"):
    data = await fetch_from_valorant("/agents", params={"language": language, "isPlayableCharacter": "true"})
    agents = data.get("data", [])
    match = next((a for a in agents if a["displayName"].lower() == name.lower()), None)
    if not match:
        available = [a["displayName"] for a in agents]
        raise HTTPException(status_code=404, detail={"message": f"Character '{name}' not found.", "available_characters": available})
    abilities = [
        {"slot": ab.get("slot"), "name": ab.get("displayName"), "description": ab.get("description"), "icon": ab.get("displayIcon")}
        for ab in match.get("abilities", [])
    ]
    return {
        "uuid": match["uuid"],
        "name": match["displayName"],
        "role": match.get("role", {}).get("displayName") if match.get("role") else None,
        "role_icon": match.get("role", {}).get("displayIcon") if match.get("role") else None,
        "description": match.get("description"),
        "portrait": match.get("fullPortraitV2") or match.get("fullPortrait"),
        "icon": match.get("displayIcon"),
        "background": match.get("background"),
        "background_gradient_colors": match.get("backgroundGradientColors", []),
        "abilities": abilities,
    }


